import { MessageEvent } from '@nitrots/nitro-renderer';
import { OpenFishingModuleMessageParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/OpenFishingModuleParser';

export class OpenFishingModuleMessageEvent extends MessageEvent {
    constructor(callBack: (event: OpenFishingModuleMessageEvent) => void) {
        super(callBack, OpenFishingModuleMessageParser);
    }

    public getParser(): OpenFishingModuleMessageParser {
        return this.parser as OpenFishingModuleMessageParser;
    }
}
